import { WorkflowContext, KnowledgeRetrievalNode } from 'mastra';

// Add to your Mastra workflow node
const detectRetrievalQuality = async (ctx: WorkflowContext) => {
  const retrievalNode = ctx.getNode('knowledge_retrieval') as KnowledgeRetrievalNode;
  const results = await retrievalNode.retrieve(ctx.input);

  const avgScore = results.reduce((sum, doc) => sum + (doc.metadata?.score || 0), 0) / results.length;

  if (avgScore < 0.75) {
    console.warn('LOW RETRIEVAL QUALITY', { avgScore, query: ctx.input });
    ctx.setFlag('poor_retrieval', true);
  }

  return { ...ctx.input, retrievals: results };
};

import { AgentMemory, WorkflowStep } from 'mastra';

const checkMemoryStaleness = async (memory: AgentMemory, queryTime: Date) => {
  const staleThreshold = 24 * 60 * 60 * 1000; // 24 hours
  const memoryEntries = await memory.getRecent();

  const staleCount = memoryEntries.filter(entry => 
    (queryTime.getTime() - new Date(entry.timestamp).getTime()) > staleThreshold
  ).length;

  if (staleCount > memoryEntries.length * 0.5) {
    throw new Error(`Stale memory detected: ${staleCount}/${memoryEntries.length} entries`);
  }

  return memoryEntries;
};

import { KnowledgeBase, VectorDocument } from 'mastra';

const detectEmbeddingDrift = async (kb: KnowledgeBase, sampleQuery: string) => {
  const testEmbedding = await kb.embed(sampleQuery);
  const similarDocs = await kb.similaritySearch(sampleQuery, 5);

  const relevanceScores = similarDocs.map(doc => doc.score);
  const stdDev = Math.sqrt(relevanceScores.reduce((sum, s, i) => 
    sum + Math.pow(s - relevanceScores.reduce((a, b) => a + b) / relevanceScores.length, 2), 0) / relevanceScores.length
  );

  if (stdDev > 0.15) {
    console.error('Embedding drift detected', { stdDev, scores: relevanceScores });
    return false;
  }

  return true;
};

