import { AgentMemory, ContextFusionStrategy } from 'mastra';

const freshContextFusion: ContextFusionStrategy = {
  fuse: async (memory: AgentMemory[], retrievals: any[], query: string) => {
    const now = Date.now();
    const freshnessWeight = 0.7;

    const weightedContexts = [
      ...retrievals.map(doc => ({ ...doc, weight: doc.metadata?.score || 0.5 })),
      ...memory
        .filter(mem => (now - new Date(mem.timestamp).getTime()) < 12 * 60 * 60 * 1000)
        .map(mem => ({ ...mem, weight: freshnessWeight }))
    ];

    return weightedContexts
      .sort((a, b) => b.weight - a.weight)
      .slice(0, 8);
  }
};

import { KnowledgeBase } from 'mastra';

const adaptiveChunking = async (kb: KnowledgeBase, query: string) => {
  const queryComplexity = query.split(' ').length + (query.match(/technical|code|api/g) || []).length;
  let chunkSize = queryComplexity > 15 ? 2048 : 1024;
  let overlap = chunkSize / 8;

  // Test retrieval quality and adjust
  let results = await kb.retrieve(query, { chunkSize, overlap });
  let avgScore = results.reduce((sum, r) => sum + (r.score || 0), 0) / results.length;

  if (avgScore < 0.75) {
    chunkSize *= 0.8;
    overlap *= 1.2;
    results = await kb.retrieve(query, { chunkSize, overlap });
  }

  return { chunkSize, overlap, results };
};

