import { Vex } from '@vex_dev/sdk';
import { MastraAgent, WorkflowContext } from 'mastra';

const vex = new Vex({
  projectId: 'your-project-id',
  agentId: 'mastra-rag-agent'
});

const mastraAgent = new MastraAgent({
  // your config
});

// Vex middleware integration
mastraAgent.useMiddleware(async (ctx: WorkflowContext, next) => {
  // Capture retrieval metrics
  if (ctx.currentNode?.type === 'KNOWLEDGE_RETRIEVAL') {
    const start = Date.now();
    const results = ctx.currentNode.output;

    vex.captureRetrieval({
      query: ctx.input,
      results,
      avgScore: results.reduce((sum, r) => sum + r.score, 0) / results.length,
      latency: Date.now() - start
    });
  }

  // Auto-remediate low quality
  if (ctx.flags?.poor_retrieval) {
    vex.triggerRemediation('RAG_QUALITY_DROP', {
      agentId: mastraAgent.id,
      fix: 'increase_chunk_size',
      threshold: 0.8
    });
  }

  return next(ctx);
});

// Vex auto-configures optimal thresholds
vex.autoOptimizeRAG(mastraAgent, {
  minRelevance: 0.8,
  maxStaleness: '24h',
  embeddingDriftThreshold: 0.15
});
